function projects_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('projects');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'category' => Request::val('category', 'PRAYAS'),
		'collaboration_partner_type' => Request::val('collaboration_partner_type', 'Institute'),
		'collaboration_partner_name' => Request::val('collaboration_partner_name', ''),
		'project_title' => Request::val('project_title', ''),
		'trl_level' => Request::val('trl_level', 'TRL 1'),
		'project_status' => Request::val('project_status', 'Ongoing'),
		'project_commercialized' => Request::val('project_commercialized', 'No'),
		'brief_of_the_project' => br2nl(Request::val('brief_of_the_project', '')),
		'commercialization_areas' => Request::val('commercialization_areas', ''),
		'targeted_sdg' => Request::val('targeted_sdg', ''),
		'total_approved_amount' => Request::val('total_approved_amount', ''),
		'funding_released_2020' => Request::val('funding_released_2020', ''),
		'funding_released_2021' => Request::val('funding_released_2021', ''),
		'funding_released_2022' => Request::val('funding_released_2022', ''),
		'funding_released_2023' => Request::val('funding_released_2023', ''),
		'funding_released_2024' => Request::val('funding_released_2024', ''),
		'funding_released_2025' => Request::val('funding_released_2025', ''),
		'funding_released_2026' => Request::val('funding_released_2026', ''),
		'funding_released_2027' => Request::val('funding_released_2027', ''),
		'total_value_released' => Request::val('total_value_released', ''),
		'external_funding_amount' => Request::val('external_funding_amount', ''),
		'remarks' => br2nl(Request::val('remarks', '')),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('projects', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		projects_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function projects_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

