function projects_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('projects', $selected_id, 'edit')) return false;

	$data = [
		'category' => Request::val('category', ''),
		'collaboration_partner_type' => Request::val('collaboration_partner_type', ''),
		'collaboration_partner_name' => Request::val('collaboration_partner_name', ''),
		'project_title' => Request::val('project_title', ''),
		'trl_level' => Request::val('trl_level', ''),
		'project_status' => Request::val('project_status', ''),
		'project_commercialized' => Request::val('project_commercialized', ''),
		'brief_of_the_project' => br2nl(Request::val('brief_of_the_project', '')),
		'commercialization_areas' => Request::val('commercialization_areas', ''),
		'targeted_sdg' => Request::val('targeted_sdg', ''),
		'total_approved_amount' => Request::val('total_approved_amount', ''),
		'funding_released_2020' => Request::val('funding_released_2020', ''),
		'funding_released_2021' => Request::val('funding_released_2021', ''),
		'funding_released_2022' => Request::val('funding_released_2022', ''),
		'funding_released_2023' => Request::val('funding_released_2023', ''),
		'funding_released_2024' => Request::val('funding_released_2024', ''),
		'funding_released_2025' => Request::val('funding_released_2025', ''),
		'funding_released_2026' => Request::val('funding_released_2026', ''),
		'funding_released_2027' => Request::val('funding_released_2027', ''),
		'total_value_released' => Request::val('total_value_released', ''),
		'external_funding_amount' => Request::val('external_funding_amount', ''),
		'remarks' => br2nl(Request::val('remarks', '')),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
	];

	if($data['collaboration_partner_name'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Collaboration Partner Name': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['project_title'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Project title': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('projects', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: projects_before_update
	if(function_exists('projects_before_update')) {
		$args = ['old_data' => $old_data];
		if(!projects_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'projects',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="projects_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('projects', $data['selectedID'], calculated_fields()['projects']);

	// hook: projects_after_update
	if(function_exists('projects_after_update')) {
		if($row = getRecord('projects', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!projects_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('projects', $selected_id);
}

